  paths: [
  {"id":"beast","name":"The Beast","description":"Full path to The Beast (Dogma + Beast fight)","steps":[{"id":"s1","label":"Defeat Mom (Foot)"},{"id":"s2","label":"Get the Negative or Polaroid"},{"id":"s3","label":"Defeat Mom's Heart / It Lives (11 times to unlock door)"},{"id":"s4","label":"Go to Mausoleum (use knife pieces or Dad's Note)"},{"id":"s5","label":"Defeat Mom (Mausoleum)"},{"id":"s6","label":"Enter the crack to Gehenna II"},{"id":"s7","label":"Defeat the four Horsemen (Famine, Pestilence, War, Death)"},{"id":"s8","label":"Pick up Dad's Note"},{"id":"s9","label":"Go to Home"},{"id":"s10","label":"Defeat Dogma, then The Beast"}]},
  {"id":"mega-satan","name":"Mega Satan","description":"Path to Mega Satan (two key pieces)","steps":[{"id":"s1","label":"Defeat Mom's Heart / It Lives"},{"id":"s2","label":"Get Angel Room (skip first Devil Deal or use sacrifice)"},{"id":"s3","label":"Fight and defeat Angel for Key Piece 1"},{"id":"s4","label":"Get second Angel Room (next floor or sacrifice)"},{"id":"s5","label":"Fight and defeat Angel for Key Piece 2"},{"id":"s6","label":"Reach The Chest or Dark Room"},{"id":"s7","label":"Use both key pieces on the large golden door"},{"id":"s8","label":"Defeat Mega Satan"}]},
  {"id":"mother","name":"Mother","description":"Path to Mother (Alt path)","steps":[{"id":"s1","label":"Defeat Mom (Foot)"},{"id":"s2","label":"Go to Downpour II (alt path)"},{"id":"s3","label":"Get the knife piece in the mirror world"},{"id":"s4","label":"Continue alt path through Mines II, Mausoleum II"},{"id":"s5","label":"Defeat Mom (Mausoleum) for second knife piece"},{"id":"s6","label":"Assemble the knife"},{"id":"s7","label":"Go to Corpse II"},{"id":"s8","label":"Use knife on the flesh door"},{"id":"s9","label":"Defeat Mother"}]},
  {"id":"hush","name":"Hush","description":"Path to Hush (Blue Womb)","steps":[{"id":"s1","label":"Defeat Mom's Heart / It Lives at least once (unlocks Blue Womb)"},{"id":"s2","label":"In a single run, defeat It Lives within 30 minutes"},{"id":"s3","label":"A trapdoor appears; enter to go to Blue Womb"},{"id":"s4","label":"Clear Blue Womb I (two rooms)"},{"id":"s5","label":"Enter the boss room and defeat Hush"}]},
  {"id":"delirium","name":"Delirium","description":"Path to Delirium (Void)","steps":[{"id":"s1","label":"Unlock the Void (defeat Hush once)"},{"id":"s2","label":"After defeating Hush, a portal to the Void can appear"},{"id":"s3","label":"Or: portal can appear after Mega Satan, Boss Rush, or Mom"},{"id":"s4","label":"Enter the Void portal"},{"id":"s5","label":"Navigate the Void (find the boss room)"},{"id":"s6","label":"Defeat Delirium"}]},
  {"id":"corpse","name":"Corpse","description":"Path to Corpse (alt path floors)","steps":[{"id":"s1","label":"Defeat Mom (Foot)"},{"id":"s2","label":"Go to Downpour II via alt path"},{"id":"s3","label":"Get first knife piece in mirror world (Downpour II)"},{"id":"s4","label":"Continue to Mines II, get second knife piece (Mausoleum Mom)"},{"id":"s5","label":"Assemble the knife"},{"id":"s6","label":"Go to Mausoleum II and use knife on the flesh door"},{"id":"s7","label":"Enter Corpse I"},{"id":"s8","label":"Clear Corpse I and go to Corpse II"},{"id":"s9","label":"Optional: defeat Mother at end of Corpse II"}]},
  {"id":"lamb","name":"The Lamb","description":"Path to The Lamb (Dark Room)","steps":[{"id":"s1","label":"Defeat Mom's Heart / It Lives"},{"id":"s2","label":"Take the Negative (not the Polaroid)"},{"id":"s3","label":"Go to Sheol via the trapdoor"},{"id":"s4","label":"Defeat Satan in Sheol"},{"id":"s5","label":"The Negative activates — enter the chest to go to Dark Room"},{"id":"s6","label":"Navigate Dark Room to the boss room"},{"id":"s7","label":"Defeat The Lamb"}]},
  {"id":"chest","name":"??? (Chest)","description":"Path to ??? in The Chest","steps":[{"id":"s1","label":"Defeat Mom's Heart / It Lives"},{"id":"s2","label":"Take the Polaroid (not the Negative)"},{"id":"s3","label":"After It Lives, go to Cathedral (beam of light)"},{"id":"s4","label":"Defeat Isaac in Cathedral"},{"id":"s5","label":"Enter the golden gate to The Chest"},{"id":"s6","label":"Defeat ??? (Blue Baby)"}]},
  {"id":"isaac","name":"Isaac (Cathedral)","description":"Path to Isaac in Cathedral","steps":[{"id":"s1","label":"Defeat Mom's Heart / It Lives"},{"id":"s2","label":"Take the Polaroid"},{"id":"s3","label":"Go to Cathedral via the beam of light"},{"id":"s4","label":"Defeat Isaac"}]},
  {"id":"satan","name":"Satan (Sheol)","description":"Path to Satan in Sheol","steps":[{"id":"s1","label":"Defeat Mom's Heart / It Lives"},{"id":"s2","label":"Take the Negative"},{"id":"s3","label":"Go to Sheol via the trapdoor"},{"id":"s4","label":"Defeat Satan"}]},
  {"id":"boss-rush","name":"Boss Rush","description":"How to reach Boss Rush","steps":[{"id":"s1","label":"Defeat Mom (Foot) for the first time in the run"},{"id":"s2","label":"Do it within 20 minutes (timer starts at run start)"},{"id":"s3","label":"A big door opens in the Mom boss room"},{"id":"s4","label":"Enter and defeat all waves (Boss Rush)"}]},
  {"id":"greed","name":"Greed Mode","description":"Greed Mode and Ultra Greed","steps":[{"id":"s1","label":"Select Greed Mode from the main menu (available after defeating Mom)"},{"id":"s2","label":"Start a run in Greed Mode"},{"id":"s3","label":"Clear each floor (waves of enemies, then boss)"},{"id":"s4","label":"Reach the final floor (The Shop)"},{"id":"s5","label":"Defeat Ultra Greed"},{"id":"s6","label":"Optional: defeat Ultra Greedier (unlocked by donating 500+ coins to the Greed Donation Machine)"}]}
],

